import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface CompetitorPrice {
  competitor: string;
  price: number;
}

interface ProductData {
  product: {
    name: string;
    currentPrice: number;
    competitorPrices: CompetitorPrice[];
  };
  priceTrend: number[];
}

export default function Widget() {
  const productData = response.data as ProductData;
  const { product, priceTrend } = productData;
  const lowestCompetitorPrice = Math.min(...product.competitorPrices.map(cp => cp.price));
  const priceDifference = product.currentPrice - lowestCompetitorPrice;
  const isCurrentPriceLowest = priceDifference <= 0;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#2C2C2C' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107', mb: 1 }}>
              {product.name}
            </Typography>
            <Typography variant="h4" sx={{ color: '#FFFFFF', fontWeight: 600 }}>
              ${product.currentPrice.toFixed(2)}
            </Typography>
            <Typography variant="body2" sx={{ color: isCurrentPriceLowest ? '#4CAF50' : '#FF5722' }}>
              {isCurrentPriceLowest ? 'Lowest Price Available' : `Save $${priceDifference.toFixed(2)} with competitors`}
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {product.competitorPrices.slice(0, 3).map((competitorPrice, index) => (
              <Chip
                key={index}
                label={`${competitorPrice.competitor}: $${competitorPrice.price.toFixed(2)}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#424242', color: '#FFC107' }}
              />
            ))}
          </Stack>

          <Box>
            <LineChart
              height={120}
              series={[
                {
                  data: priceTrend,
                  color: '#FFC107',
                  curve: 'natural',
                  showMark: false,
                },
              ]}
              xAxis={[{ data: [0, 1, 2, 3, 4], hide: true }]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
